import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Line, Bar } from "react-chartjs-2";
import "./PriceAnalytics.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = "http://localhost:7000/api";

const PriceAnalytics = () => {
  const [loading, setLoading] = useState(true);
  const [productList, setProductList] = useState([]);
  const [categoryList, setCategoryList] = useState([]);
  const [selectedProduct, setSelectedProduct] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("");
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  const [productData, setProductData] = useState([]);
  const [categoryData, setCategoryData] = useState([]);

  // 🔹 Fetch dropdown data
  useEffect(() => {
    const fetchLists = async () => {
      try {
        const [productsRes, catsRes] = await Promise.all([
          axios.get(`${API_BASE}/prices`),
          axios.get(`${API_BASE}/categories`),
        ]);
        setProductList(Array.isArray(productsRes.data) ? productsRes.data : []);
        setCategoryList(Array.isArray(catsRes.data) ? catsRes.data : []);
      } catch (err) {
        console.error("Dropdown fetch error:", err);
        setProductList([]);
        setCategoryList([]);
      }
    };
    fetchLists();
  }, []);

  // 🔹 Fetch trends (by custom date range)
  const fetchTrends = async () => {
    setLoading(true);
    try {
      const queryDates =
        startDate && endDate
          ? `&start=${startDate}&end=${endDate}`
          : "";

      const [prodRes, catRes] = await Promise.all([
        axios.get(
          `${API_BASE}/price-report/trends?type=product${queryDates}${
            selectedProduct ? `&filter=${selectedProduct}` : ""
          }`
        ),
        axios.get(
          `${API_BASE}/price-report/trends?type=category${queryDates}${
            selectedCategory ? `&filter=${selectedCategory}` : ""
          }`
        ),
      ]);

      setProductData(Array.isArray(prodRes.data) ? prodRes.data : []);
      setCategoryData(Array.isArray(catRes.data) ? catRes.data : []);
    } catch (err) {
      console.error("Error fetching trends:", err);
      setProductData([]);
      setCategoryData([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchTrends();
  }, [selectedProduct, selectedCategory, startDate, endDate]);

  // 🔹 Product Line Chart
  const lineChartData = {
    labels:
      productData.length > 0
        ? [...new Set(productData.flatMap((d) => d.prices.map((p) => p.date)))].sort()
        : [],
    datasets:
      productData.length > 0
        ? productData.flatMap((p, i) => [
            {
              label: `${p._id} - Avg Price`,
              data: p.prices.map((pr) => pr.avgPrice),
              borderColor: `hsl(${i * 40}, 70%, 50%)`,
              backgroundColor: `hsla(${i * 40}, 70%, 60%, 0.2)`,
              tension: 0.4,
              fill: false,
            },
            {
              label: `${p._id} - Δ Price`,
              data: p.prices.map((pr) => pr.difference || 0),
              borderColor: `hsl(${i * 40 + 180}, 70%, 50%)`,
              backgroundColor: `hsla(${i * 40 + 180}, 70%, 60%, 0.2)`,
              borderDash: [6, 3],
              tension: 0.4,
              fill: false,
            },
          ])
        : [],
  };

  // 🔹 Category Bar Chart
  const barChartData = {
    labels:
      categoryData.length > 0
        ? [...new Set(categoryData.flatMap((d) => d.prices.map((p) => p.date)))].sort()
        : [],
    datasets:
      categoryData.length > 0
        ? categoryData.flatMap((c, i) => [
            {
              label: `${c._id} - Avg Price`,
              data: c.prices.map((pr) => pr.avgPrice),
              backgroundColor: `hsla(${i * 60}, 70%, 60%, 0.7)`,
            },
            {
              label: `${c._id} - Δ Price`,
              data: c.prices.map((pr) => pr.difference || 0),
              backgroundColor: `hsla(${i * 60 + 180}, 70%, 60%, 0.7)`,
            },
          ])
        : [],
  };

  return (
    <div className="analytics-container">
      <h2 className="analytics-title">📊 Price Analytics Dashboard</h2>

      {/* 🔹 Filters */}
      <div className="filter-row">
        <div className="filter-group">
          <label>🗓️ From:</label>
          <input
            type="date"
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
          />
        </div>

        <div className="filter-group">
          <label>➡️ To:</label>
          <input
            type="date"
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
          />
        </div>

        <button className="refresh-btn" onClick={fetchTrends}>
          🔄 Refresh
        </button>
      </div>

      {loading ? (
        <div className="no-data">Loading analytics...</div>
      ) : (
        <div className="chart-grid">
          {/* Product Chart */}
          <div className="chart-card">
            <div className="chart-header">
              <h3 className="chart-title">📈 Product-wise Trends</h3>
              <select
                className="dropdown-select"
                value={selectedProduct}
                onChange={(e) => setSelectedProduct(e.target.value)}
              >
                <option value="">All Products</option>
                {productList.map((p) => (
                  <option key={p._id} value={p.name}>
                    {p.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {lineChartData.labels.length > 0 ? (
                <Line
                  data={lineChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { position: "bottom" } },
                    scales: { y: { beginAtZero: true } },
                  }}
                />
              ) : (
                <p className="no-data">No product data</p>
              )}
            </div>
          </div>

          {/* Category Chart */}
          <div className="chart-card">
            <div className="chart-header">
              <h3 className="chart-title">📉 Category-wise Trends</h3>
              <select
                className="dropdown-select"
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
              >
                <option value="">All Categories</option>
                {categoryList.map((c) => (
                  <option key={c._id} value={c.name}>
                    {c.name}
                  </option>
                ))}
              </select>
            </div>
            <div className="chart-container">
              {barChartData.labels.length > 0 ? (
                <Bar
                  data={barChartData}
                  options={{
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { position: "bottom" } },
                    scales: { y: { beginAtZero: true } },
                  }}
                />
              ) : (
                <p className="no-data">No category data</p>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PriceAnalytics;
